import path from 'node:path'

/** @type {import('next').NextConfig} */
const nextConfig = {
  webpack: (config, { isServer }) => {
    config.experiments = {
      ...config.experiments,
      asyncWebAssembly: true,
      topLevelAwait: true,
    }

    config.module.rules.push({
      test: /\.wasm$/,
      type: 'webassembly/async',
    })

    config.resolve = {
      ...config.resolve,
      alias: {
        ...config.resolve?.alias,
        '@nimiq/core': path.resolve('./node_modules/@nimiq/core/bundler/index.js'),
      },
      fallback: {
        ...config.resolve?.fallback,
        path: false,
        fs: false,
      },
      extensions: [...(config.resolve?.extensions || []), '.js', '.mjs'],
    }

    if (!isServer) {
      config.optimization = {
        ...config.optimization,
        splitChunks: {
          ...config.optimization?.splitChunks,
          cacheGroups: {
            ...(config.optimization?.splitChunks)?.cacheGroups,
            nimiq: {
              test: /@nimiq/,
              name: 'nimiq',
              chunks: 'all',
              priority: 10,
            },
          },
        },
      }
    }

    return config
  },
}

module.exports = nextConfig

import { Client, ClientConfiguration } from '@nimiq/core'
import { useEffect, useState } from 'react'

export function useNimiq() {
  const [client, setClient] = useState<Client | null>(null)
  const [blockHeight, setBlockHeight] = useState(0)
  const [isConnecting, setIsConnecting] = useState(false)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let mounted = true

    async function init() {
      setIsConnecting(true)
      try {
        const config = new ClientConfiguration()
        const nimiqClient = await Client.create(config.build())
        await nimiqClient.waitForConsensusEstablished()

        if (mounted) {
          setClient(nimiqClient)
          setBlockHeight(await nimiqClient.getBlockNumber())
        }
      }
      catch (err) {
        if (mounted)
          setError(err instanceof Error ? err.message : 'Failed to connect')
      }
      finally {
        if (mounted)
          setIsConnecting(false)
      }
    }

    init()
    return () => {
      mounted = false
    }
  }, [])

  return { client, blockHeight, isConnecting, error }
}

import { useNimiq } from '../hooks/useNimiq'

export default function Wallet() {
  const { client, blockHeight, isConnecting, error } = useNimiq()

  if (isConnecting)
    return <p>Connecting to blockchain...</p>
  if (error) {
    return (
      <p>
        Error:
        {error}
      </p>
    )
  }

  return (
    <div>
      <h1>Nimiq Wallet</h1>
      <p>
        Block Height:
        {blockHeight.toLocaleString()}
      </p>
      <p>
        Network:
        {client?.getNetworkId()}
      </p>
    </div>
  )
}
